// Browser shim for Chalk - provides ANSI color support
// Generates proper ANSI escape codes for xterm

// ANSI escape codes
const ANSI_CODES = {
  // Modifiers
  reset: [0, 0],
  bold: [1, 22],
  dim: [2, 22],
  italic: [3, 23],
  underline: [4, 24],
  inverse: [7, 27],
  strikethrough: [9, 29],

  // Foreground colors
  black: [30, 39],
  red: [31, 39],
  green: [32, 39],
  yellow: [33, 39],
  blue: [34, 39],
  magenta: [35, 39],
  cyan: [36, 39],
  white: [37, 39],
  gray: [90, 39],
  grey: [90, 39],

  // Bright foreground colors
  blackBright: [90, 39],
  redBright: [91, 39],
  greenBright: [92, 39],
  yellowBright: [93, 39],
  blueBright: [94, 39],
  magentaBright: [95, 39],
  cyanBright: [96, 39],
  whiteBright: [97, 39],

  // Background colors
  bgBlack: [40, 49],
  bgRed: [41, 49],
  bgGreen: [42, 49],
  bgYellow: [43, 49],
  bgBlue: [44, 49],
  bgMagenta: [45, 49],
  bgCyan: [46, 49],
  bgWhite: [47, 49],

  // Bright background colors
  bgBlackBright: [100, 49],
  bgRedBright: [101, 49],
  bgGreenBright: [102, 49],
  bgYellowBright: [103, 49],
  bgBlueBright: [104, 49],
  bgMagentaBright: [105, 49],
  bgCyanBright: [106, 49],
  bgWhiteBright: [107, 49],
} as const

const wrapAnsi = (code: number, str: string, resetCode: number) => {
  return `\u001b[${code}m${str}\u001b[${resetCode}m`
}

const createChalkInstance = () => {
  const chalk: any = (str: string) => str

  // Create methods for each ANSI code
  Object.entries(ANSI_CODES).forEach(([name, [open, close]]) => {
    chalk[name] = (str: string) => wrapAnsi(open, str, close)

    // Create a builder that supports chaining
    const builder: any = (str: string) => wrapAnsi(open, str, close)

    // Add all color methods to the builder for chaining
    Object.entries(ANSI_CODES).forEach(([innerName, [innerOpen, innerClose]]) => {
      builder[innerName] = (str: string) => wrapAnsi(open, wrapAnsi(innerOpen, str, innerClose), close)
    })

    chalk[name] = Object.assign(builder, builder)
  })

  chalk.level = 3
  chalk.supportsColor = { level: 3, hasBasic: true, has256: true, has16m: true }

  return chalk
}

const chalk = createChalkInstance()
export default chalk
